type IconName = keyof typeof PATHS;

type Props = {
  name: IconName;
  className?: string;
  size?: number;
  "aria-hidden"?: boolean;
};

export function Icon({ name, className = "", size = 24, "aria-hidden": ariaHidden }: Props) {
  const customContent = SIDEBAR_ICON_CONTENT[name];
  const path = PATHS[name];

  if (customContent) {
    return (
      <span className={`inline-block shrink-0 select-none ${className}`} aria-hidden={ariaHidden}>
        <svg
          xmlns="http://www.w3.org/2000/svg"
          viewBox="0 0 24 24"
          width={size}
          height={size}
          fill="none"
          className="block"
          style={{ color: "inherit" }}
        >
          {customContent}
        </svg>
      </span>
    );
  }

  if (!path) return null;
  return (
    <span className={`inline-block shrink-0 select-none ${className}`} aria-hidden={ariaHidden}>
      <svg
        xmlns="http://www.w3.org/2000/svg"
        viewBox="0 0 24 24"
        width={size}
        height={size}
        fill="currentColor"
        className="block"
      >
        <path d={path} />
      </svg>
    </span>
  );
}
